// --- HELPERS & MAPPERS ---
function mapDbToRecord(dbEvent: any) {
  return {
    title: dbEvent.title,
    eventName: dbEvent.title,
    slug: dbEvent.slug,
    category: dbEvent.category.toLowerCase(),
    canonicalSlug: `${dbEvent.category.toLowerCase()}/${dbEvent.slug}`,
    description: dbEvent.seoDescription || dbEvent.description || undefined,
    dueAt: dbEvent.dueAt?.toISOString() || undefined,
    statusLabel: dbEvent.dateStatus === 'EXACT' ? 'CONFIRMED' : 'EXPECTED',
    seriesKey: dbEvent.seriesId || undefined,
    sourceUrl: dbEvent.sourceUrl || undefined,
    lastVerifiedUtc: dbEvent.lastVerified?.toISOString() || dbEvent.updatedAt.toISOString(),
    updatedAt: dbEvent.updatedAt.toISOString(),
    createdAt: dbEvent.createdAt.toISOString(),
    eventId: dbEvent.id, 
    eventType: dbEvent.category === "FEDERAL" ? "SCHEDULE" : "EVENT",
    officialDates: [], 
    dateStatus: dbEvent.dateStatus,
    timeZone: dbEvent.timeZone,
    dateLabel: dbEvent.dateLabel,
    
    // Intelligence Fields
    shortSummary: dbEvent.shortSummary || undefined,
    whatToExpect: dbEvent.whatToExpect || undefined,
    whereToWatch: dbEvent.whereToWatch || undefined,
    expectedDuration: dbEvent.expectedDuration || undefined,
    targetAudience: dbEvent.targetAudience || undefined,
  };
}

async function loadAnomalyCatalog(program: string | null) {
  if (!program) return null;
  try {
    const name = program === "SSA" ? "anomalyCatalog.ssa.json" : 
                 program === "VA" ? "anomalyCatalog.va.json" : 
                 "anomalyCatalog.snap.json";
    const jsonPath = path.resolve(process.cwd(), `data/${name}`);
    const raw = await fs.readFile(jsonPath, "utf8");
    return JSON.parse(raw);
  } catch (e) { return null; }
}

// --- SMART METADATA ROUTER ---
export async function generateMetadata({ params }: { params: Promise<{ category: string; slug: string }> }): Promise<Metadata> {
  const { slug, category } = await params;
  const dbEvent = await prisma.event.findUnique({ where: { slug: slug.toLowerCase() } });
  if (dbEvent) return buildEventMetadata(dbEvent);

  const dbSeries = await prisma.eventSeries.findUnique({ where: { slugBase: slug.toLowerCase() } });
  if (dbSeries) {
    const title = `${dbSeries.title} Schedule & Exact Dates | ${SITE_NAME}`;
    const description = `Track the complete ${dbSeries.title} schedule.`;
    return {
      title,
      description,
      alternates: { canonical: `https://whenisdue.com/${category.toLowerCase()}/${slug.toLowerCase()}` },
      openGraph: { title, description, type: "website", siteName: SITE_NAME }
    };
  }
  return { title: "Not found", robots: { index: false, follow: false } };
}

// --- SMART PAGE ROUTER ---
export default async function SmartRoutePage({ params }: { params: Promise<{ category: string; slug: string }> }) {
  const { category, slug } = await params;
  const dbEvent = await prisma.event.findUnique({ 
    where: { slug: slug.toLowerCase() },
    include: { series: true } 
  });
  if (dbEvent) return <SingleEventView dbEvent={dbEvent} category={category} slug={slug} />;

  const dbSeries = await prisma.eventSeries.findUnique({
    where: { slugBase: slug.toLowerCase() },
    include: { events: { orderBy: { dueAt: 'asc' } } }
  });
  if (dbSeries) return <SeriesEvergreenView series={dbSeries} category={category} />;
  notFound();
}

